def contar_ate_sentinela(valores, marcador):
    i = 0
    while i < len(valores) and valores[i] != marcador:
        i += 1
    return i

print(contar_ate_sentinela([4, 5, 0, 9], 0))   # 2 (achou o 0 no índice 2)

def resumo_alertas(valores, limite):
    soma = 0
    qtd = 0
    for v in valores:
        soma += v
        if v >= limite:
            qtd += 1
    return soma, qtd

soma, qtd = resumo_alertas([12, 80, 51, 9], 50)
print("Soma:", soma, "  Críticos:", qtd)

def pedir_positivo(rotulo):
    while True:
        n = int(input(f"{rotulo}: "))
        if n > 0:
            return n
        print("Inválido. Tente novamente.")

idade = pedir_positivo("Idade")
print("Idade aceita:", idade)
